cat > /tmp/explore_api.cs << 'EOF'
using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

var agentsPath = "/home/runner/.nuget/packages/microsoft.agents.ai/1.6.1/lib/net10.0/Microsoft.Agents.AI.dll";
var extensionsPath = "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.1/lib/net10.0/Microsoft.Extensions.AI.dll";

// Load assemblies
var agentsAssembly = Assembly.LoadFrom(agentsPath);
var extensionsAssembly = Assembly.LoadFrom(extensionsPath);

Console.WriteLine("========== MICROSOFT.AGENTS.AI TYPES ==========\n");

// Find types with Agent or Worker
var agentTypes = agentsAssembly.GetTypes()
    .Where(t => t.Name.Contains("Agent") || t.Name.Contains("Worker"))
    .OrderBy(t => t.Name)
    .ToList();

foreach (var type in agentTypes)
{
    Console.WriteLine($"\n[CLASS] {type.FullName}");

    // Constructors
    var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    if (ctors.Length > 0)
    {
        Console.WriteLine("  Constructors:");
        foreach (var ctor in ctors)
        {
            var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    {type.Name}({parms})");
        }
    }

    // Key methods
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => m.Name.Contains("Invoke") || m.Name.Contains("Run") || m.Name.Contains("Execute"))
        .ToList();

    if (methods.Count > 0)
    {
        Console.WriteLine("  Methods:");
        foreach (var method in methods.DistinctBy(m => m.Name))
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({parms})");
        }
    }

    // Properties
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    if (props.Length > 0)
    {
        Console.WriteLine("  Properties:");
        foreach (var prop in props.Take(5))
        {
            Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name}");
        }
        if (props.Length > 5) Console.WriteLine($"    ... and {props.Length - 5} more");
    }
}

Console.WriteLine("\n========== MICROSOFT.EXTENSIONS.AI TOOL-RELATED TYPES ==========\n");

// Find tool-related types
var toolTypes = extensionsAssembly.GetTypes()
    .Where(t => t.Name.Contains("Tool") || t.Name.Contains("Function") || t.Name.Contains("ChatClient") || t.Name.Contains("ChatOptions"))
    .Where(t => !t.Name.StartsWith("<"))
    .OrderBy(t => t.Name)
    .ToList();

foreach (var type in toolTypes)
{
    Console.WriteLine($"\n[CLASS] {type.FullName}");

    // Constructors
    var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    if (ctors.Length > 0)
    {
        Console.WriteLine("  Constructors:");
        foreach (var ctor in ctors.Take(3))
        {
            var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    {type.Name}({parms})");
        }
        if (ctors.Length > 3) Console.WriteLine($"    ... and {ctors.Length - 3} more");
    }

    // Key methods
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .ToList();

    if (methods.Count > 0)
    {
        Console.WriteLine("  Methods:");
        foreach (var method in methods.DistinctBy(m => m.Name).Take(5))
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({parms})");
        }
        if (methods.Count > 5) Console.WriteLine($"    ... and {methods.Count - 5} more");
    }

    // Properties
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    if (props.Length > 0)
    {
        Console.WriteLine("  Properties:");
        foreach (var prop in props.Take(3))
        {
            Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name}");
        }
        if (props.Length > 3) Console.WriteLine($"    ... and {props.Length - 3} more");
    }
}

Console.WriteLine("\n========== ALL TYPES IN MICROSOFT.AGENTS.AI ==========\n");
var allAgentTypes = agentsAssembly.GetTypes().Where(t => !t.Name.StartsWith("<")).OrderBy(t => t.Name).ToList();
Console.WriteLine($"Total types: {allAgentTypes.Count}");
Console.WriteLine(string.Join("\n", allAgentTypes.Select(t => $"  {t.FullName}")));
