using System.ComponentModel;
using System.Text;
using System.Text.Json;
using System.Web;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(
        builder.Configuration["AI:Model"] ?? "gpt-4o-mini-2024-07-18"));

builder.Services.AddSingleton<Notebook>();
builder.Services.AddSingleton<ResearchTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();

var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWebAsync),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes.",
        Instructions = """
            You are a research assistant. When given a topic:
            1. Search the web for information using multiple relevant queries.
            2. Save important findings as notes using the note-taking tool.
            3. After gathering enough information, retrieve all your notes
               and produce a well-structured summary with key points and sources.
            Be thorough — perform at least 2-3 different searches to cover
            multiple angles of the topic.
            """,
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            Tools = [.. tools],
        },
    },
    loggerFactory);

Console.WriteLine("Research Agent Starting...");
Console.Write("Enter a research topic (or press Enter for default): ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
    topic = "Recent advances in quantum computing 2025";

Console.WriteLine($"\nResearching: {topic}\n");

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: new ChatClientAgentRunOptions
    {
        MaximumIterations = 15,
    });

Console.WriteLine("═══ Research Summary ═══\n");
Console.WriteLine(response.Text);

// ----- Service classes -----

/// <summary>Simple in-memory notebook for the agent to store findings.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];
    private readonly object _lock = new();

    public void Add(string note)
    {
        lock (_lock) _notes.Add(note);
    }

    public IReadOnlyList<string> GetAll()
    {
        lock (_lock) return [.. _notes];
    }
}

/// <summary>Tools exposed to the research agent.</summary>
sealed class ResearchTools(Notebook notebook, ILogger<ResearchTools> logger)
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Web search: {Query}", query);

        try
        {
            var encoded = HttpUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url, cancellationToken);
